import { useState } from "react";
import API from "../api/api";

function PlayerStats() {
  const [name, setName] = useState("");
  const [players, setPlayers] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");

  // 🔍 Search Function
  const searchPlayer = async () => {
    if (!name.trim()) {
      setError("Please enter player name");
      return;
    }

    try {
      setLoading(true);
      setError("");
      setPlayers([]);

      const res = await API.get(`/cricket/player?name=${name}`);

      console.log("👤 PLAYER DATA:", res.data);

      setPlayers(res.data.players || []);
      setLoading(false);

    } catch (err) {
      console.log("❌ ERROR:", err.message);
      setError("Failed to fetch player");
      setLoading(false);
    }
  };

  return (
    <div className="card">
      <h2>👤 Player Stats</h2>

      {/* 🔍 Search Box */}
      <div style={{ marginBottom: "10px" }}>
        <input
          type="text"
          placeholder="Enter player name (e.g. Virat)"
          value={name}
          onChange={(e) => setName(e.target.value)}
        />

        <button onClick={searchPlayer}>Search</button>
      </div>

      {/* ⏳ Loading */}
      {loading && <p>Loading...</p>}

      {/* ❌ Error */}
      {error && <p style={{ color: "red" }}>{error}</p>}

      {/* 📭 No Data */}
      {!loading && players.length === 0 && !error && (
        <p>No player found</p>
      )}

      {/* ✅ Player Data */}
      {players.map((p, i) => (
        <div key={i} className="match-card">
          <h3>{p.name}</h3>
          <p><b>Team:</b> {p.team}</p>
          <p><b>Runs:</b> {p.runs}</p>
          <p><b>Average:</b> {p.average}</p>
        </div>
      ))}
    </div>
  );
}

export default PlayerStats;
